  1	import * as React from 'react';
  2	import { DiskMetadata } from '@odf/core/types';
  3	import { useCustomTranslation } from '@odf/shared/useCustomTranslationHook';
  4	import { humanizeBinaryBytes } from '@odf/shared/utils';
  5	import {
  6	  TableData,
  7	  useActiveColumns,
  8	  VirtualizedTable,
  9	} from '@openshift-console/dynamic-plugin-sdk';
 10	import classNames from 'classnames';
 11	import {
 12	  Modal as PfModal,
 13	  ModalProps as PfModalProps,
 14	} from '@patternfly/react-core';
 15	import { Button } from '@patternfly/react-core';
 16	import { sortable } from '@patternfly/react-table';
 17	import './disk-list-modal.scss';
 18	
 19	const tableColumnClasses = [
 20	  { className: '', id: 'name' },
 21	  { className: '', id: 'node' },
 22	  { className: classNames('pf-m-hidden', 'pf-m-visible-on-xl'), id: 'type' },
 23	  { className: classNames('pf-m-hidden', 'pf-m-visible-on-2xl'), id: 'model' },
 24	  {
 25	    className: classNames('pf-m-hidden', 'pf-m-visible-on-lg'),
 26	    id: 'capacity',
 27	  },
 28	];
 29	
 30	const DiskRow = ({ obj, activeColumnIDs }) => {
 31	  return (
 32	    <>
 33	      <TableData {...tableColumnClasses[0]} activeColumnIDs={activeColumnIDs}>
 34	        {obj.path}
 35	      </TableData>
 36	      <TableData {...tableColumnClasses[1]} activeColumnIDs={activeColumnIDs}>
 37	        {obj.node}
 38	      </TableData>
 39	      <TableData {...tableColumnClasses[2]} activeColumnIDs={activeColumnIDs}>
 40	        {obj.type || '-'}
 41	      </TableData>
 42	      <TableData
 43	        {...tableColumnClasses[3]}
 44	        className={classNames(tableColumnClasses[3].className, 'co-break-word')}
 45	        activeColumnIDs={activeColumnIDs}
 46	      >
 47	        {obj.model || '-'}
 48	      </TableData>
 49	      <TableData {...tableColumnClasses[4]} activeColumnIDs={activeColumnIDs}>
 50	        {humanizeBinaryBytes(obj.size).string || '-'}
 51	      </TableData>
 52	    </>
 53	  );
 54	};
 55	
 56	export const Modal: React.FC<ModalProps> = ({
 57	  isFullScreen = false,
 58	  className,
 59	  ...props
 60	}) => (
 61	  <PfModal
 62	    {...props}
 63	    className={classNames('ocs-modal', className)}
 64	    appendTo={() =>
 65	      isFullScreen ? document.body : document.querySelector('#modal-container')
 66	    }
 67	  />
 68	);
 69	
 70	type ModalProps = {
 71	  isFullScreen?: boolean;
 72	  ref?: React.LegacyRef<PfModal>;
 73	} & PfModalProps;
 74	
 75	export const DiskListModal: React.FC<DiskListModalProps> = ({
 76	  showDiskList,
 77	  onCancel,
 78	  disks,
 79	}) => {
 80	  const { t } = useCustomTranslation();
 81	
 82	  const DiskHeader = React.useMemo(() => {
 83	    return [
 84	      {
 85	        title: t('Name'),
 86	        sort: 'path',
 87	        transforms: [sortable],
 88	        props: { className: tableColumnClasses[0].className },
 89	        id: tableColumnClasses[0].id,
 90	      },
 91	      {
 92	        title: t('Node'),
 93	        sort: 'node',
 94	        transforms: [sortable],
 95	        props: { className: tableColumnClasses[1].className },
 96	        id: tableColumnClasses[1].id,
 97	      },
 98	      {
 99	        title: t('Type'),
100	        sort: 'type',
101	        transforms: [sortable],
102	        props: { className: tableColumnClasses[2].className },
103	        id: tableColumnClasses[2].id,
104	      },
105	      {
106	        title: t('Model'),
107	        sort: 'model',
108	        transforms: [sortable],
109	        props: { className: tableColumnClasses[3].className },
110	        id: tableColumnClasses[3].id,
111	      },
112	      {
113	        title: t('Capacity'),
114	        sort: 'size',
115	        transforms: [sortable],
116	        props: { className: tableColumnClasses[4].className },
117	        id: tableColumnClasses[4].id,
118	      },
119	    ];
120	  }, [t]);
121	
122	  const [columns] = useActiveColumns({
123	    columns: DiskHeader as any, // Todo(bipuldh): Remove any after SDK update
124	    showNamespaceOverride: false,
125	    columnManagementID: 'DISKS_LIST',
126	  });
127	
128	  return (
129	    <Modal
130	      title={t('Selected Disks')}
131	      isOpen={showDiskList}
132	      onClose={onCancel}
133	      className="ceph-ocs-install__filtered-modal"
134	      actions={[
135	        <Button key="confirm" variant="primary" onClick={onCancel}>
136	          {t('Close')}
137	        </Button>,
138	      ]}
139	    >
140	      <VirtualizedTable
141	        aria-label="Disk List"
142	        data={disks}
143	        columns={columns}
144	        Row={DiskRow}
145	        unfilteredData={disks}
146	        loaded={!!disks}
147	        loadError={false}
148	      />
149	    </Modal>
150	  );
151	};
152	
153	type DiskListModalProps = {
154	  showDiskList: boolean;
155	  disks: DiskMetadata[];
156	  onCancel: () => void;
157	};

